{"code": "import sys

def is_nice(seq):
    for i in range(len(seq) - 1):
        if i % 2 == 0 and seq[i] >= seq[i+1]:
            return False
        if i % 2 == 1 and seq[i] <= seq[i+1]:
            return False
    return True

def count_valid_swaps(seq):
    n = len(seq)
    invalid_positions = []
    for i in range(n-1):
        if (i % 2 == 0 and seq[i] >= seq[i+1]) or (i % 2 == 1 and seq[i] <= seq[i+1]):
            invalid_positions.append(i)

    from collections import defaultdict
    pos_map = defaultdict(list)
    for i, val in enumerate(seq):
        pos_map[val].append(i)

    valid_pairs = set()
    for i in invalid_positions:
        for j in invalid_positions:
            if i == j:
                continue
            if i < j:
                new_seq = seq[:i] + [seq[j]] + seq[i+1:j] + [seq[i]] + seq[j+1:]
                if is_nice(new_seq):
                    valid_pairs.add((i, j))
            else:
                new_seq = seq[:j] + [seq[i]] + seq[j+1:i] + [seq[j]] + seq[i+1:]
                if is_nice(new_seq):
                    valid_pairs.add((i, j))

    return len(valid_pairs)

def main():
    n = int(sys.stdin.readline())
    seq = list(map(int, sys.stdin.readline().split()))
    print(count_valid_swaps(seq))

if __name__ == '__main__':
    main()"}

