{"code": "import sys
import math

def read_input():
    n = int(sys.stdin.readline())
    circles = []
    for _ in range(n):
        x, y, r = map(int, sys.stdin.readline().split())
        circles.append((x, y, r))
    return circles

def compute_regions(circles):
    n = len(circles)
    regions = 1  # Start with the infinite region

    # Check for intersections between each pair of circles
    for i in range(n):
        for j in range(i + 1, n):
            x1, y1, r1 = circles[i]
            x2, y2, r2 = circles[j]
            dx = x1 - x2
            dy = y1 - y2
            d = math.hypot(dx, dy)

            # Check for intersection
            if d > r1 + r2:
                # Circles are separate, add 1 region
                regions += 1
            elif d < abs(r1 - r2):
                # One circle is entirely inside the other, add 1 region
                regions += 1
            elif d == 0 and r1 == r2:
                # Same circle, but input ensures no duplicates
                pass
            else:
                # Circles intersect, add 2 regions
                regions += 2
