def main():
    n, m = map(int, sys.stdin.readline().split())
    votes = []
    for _ in range(m):
        votes.append(list(map(int, sys.stdin.readline().split())))

    # Calculate total votes for each candidate
    total_votes = [0] * n
    for i in range(m):
        for j in range(n):
            total_votes[j] += votes[i][j]

    # The opposition candidate is the last one (index n-1)
    opposition_votes = total_votes[-1]
    other_candidates = total_votes[:-1]

    # Find the minimal number of stations to cancel
    min_canceled = m
    best_canceled = []

    # Try all subsets of stations to cancel
    from itertools import combinations
    for k in range(m+1):
        for canceled in combinations(range(m), k):
            # Calculate votes after canceling these stations
            new_votes = [0] * n
            for i in range(m):
                if i not in canceled:
                    for j in range(n):
                        new_votes[j] += votes[i][j]
            # Check if opposition is not the top
            opposition_new = new_votes[-1]
            other_new = new_votes[:-1]
            if all(opposition_new <= other_new[i] for i in range(len(other_new))):
                if k < min_canceled:
                    min_canceled = k
                    best_canceled = list(canceled)
                    break
        if min_canceled == k:
            break

    print(min_canceled)
    print(' '.join(map(str, [x+1 for x in best_canceled])))

