def is_prime_digit(digit):
    return digit in {2, 3, 5, 7}

def count_triplets_with_common_prime_digit(A):
    # Convert each number to a set of its digits
    digits_sets = [
        set(str(num)) for num in A
    ]

    # Count total number of triplets
    total_triplets = 0
    # Iterate over all possible triplets
    for i in range(len(A)):
        for j in range(i+1, len(A)):
            for k in range(j+1, len(A)):
                # Check if there is at least one common prime digit
                common_digits = digits_sets[i].intersection(digits_sets[j], digits_sets[k])
                if common_digits and any(is_prime_digit(d) for d in common_digits):
                    total_triplets += 1
    return total_triplets

def main():
