{"code": "import sys
MOD = 998244353

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    # Base case: if n == 1, answer is a[0]
    if n == 1:
        print(a[0] % MOD)
        return

    # Initialize dp table
    dp = [0] * n
    dp[0] = a[0]

    # Fill dp table
    for i in range(1, n):
        # Total ways for current position
        total = 0
        # If previous value is not the same as current value
        for prev_val in range(1, a[i-1] + 1):
            for curr_val in range(1, a[i] + 1):
                if prev_val != curr_val:
                    total += dp[i-1]
        dp[i] = total % MOD

    print(dp[-1] % MOD)

if __name__ == '__main__':
    main()"}

