import numpy as np

def is_strictly_positive(matrix):
    return all(all(x > 0 for x in row) for row in matrix)

def solve():
    n = int(sys.stdin.readline())
    a = []
    for _ in range(n):
        a.append(list(map(int, sys.stdin.readline().split())))

    # Check if the matrix is already strictly positive
    if all(all(x > 0 for x in row) for row in a):
        print("YES")
        return

    # Check for k=1 to k=20 (since a^k can't be strictly positive for k > 20 if a has zeros)
    for k in range(1, 21):
        # Compute a^k using matrix exponentiation
        mat = np.array(a, dtype=np.int64)
        mat_power = np.linalg.matrix_power(mat, k)
        if is_strictly_positive(mat_power):
            print("YES")
            return

    print("NO")

solve()"}

