def sum_proper_divisors(n):
    sum_div = 1  # 1 is a proper divisor of all numbers > 1
    sqrt_n = int(n**0.5)
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            sum_div += i
            if i != n // i:
                sum_div += n // i
    return sum_div

def is_amicable(n):
    sum1 = sum_proper_divisors(n)
    if sum1 == n:
        return False  # Perfect numbers are not amicable
    sum2 = sum_proper_divisors(sum1)
    return sum2 == n and sum1 != n

def main():
