    cases = int(input[0])
    for i in range(1, cases + 1):
        num = int(input[i])
        sum_div = sum_proper_divisors(num)
        if sum_div == num:
            print("No")
        else:
            sum_div2 = sum_proper_divisors(sum_div)
            if sum_div2 == num and sum_div != num:
                print(f"Yes, amicable with {sum_div}")
            else:
                print("No")

